mapper.select:
SELECT id, recipient_id AS recipientId, actor_id AS actorId, type, entity_type AS entityType,
       entity_id AS entityId, content, is_read AS isRead, created_at AS createdAt
FROM notifications
WHERE recipient_id = #{recipientId}
AND type = #{type}
AND id < #{lastId}
ORDER BY id DESC
LIMIT #{size}
